public class Composite {
    interface Shape { int area(); }
    static class Rect implements Shape {
        int w, h;
        Rect(int w, int h) { this.w=w; this.h=h; }
        public int area() { return w * h; }
    }
    static class Group implements Shape {
        java.util.List<Shape> shapes = new java.util.ArrayList<>();
        void add(Shape s) { shapes.add(s); }
        public int area() { return shapes.stream().mapToInt(Shape::area).sum(); }
    }
    public static void main(String[] args) {
        Group g = new Group();
        g.add(new Rect(3, 4));
        g.add(new Rect(2, 5));
        Group nested = new Group();
        nested.add(new Rect(1, 1));
        g.add(nested);
        System.out.println(g.area());
    }
}
